15	// InstallPackage downloads the source release tarball and copies declared install mappings
16	// into projectRoot. It records installed files (project-relative when possible) in the
17	// returned InstalledEntry.
18	func InstallPackage(pkg *Package, projectRoot string) (InstalledEntry, error) {
19		entry := InstalledEntry{
20			Name:        pkg.Name,
21			Version:     pkg.Version,
22			Type:        pkg.Type,
23			Source:      pkg.Source,
24			InstalledAt: time.Now(),
25		}
26	
27		// FEAT-015 early validation: if the package argument already declares a
28		// home-rooted Root.Target, reject it before doing any I/O. The post-
29		// manifest check below covers manifest-supplied targets after download.
30		if pkg.Install.Root != nil && strings.HasPrefix(pkg.Install.Root.Target, "~") {
31			return entry, fmt.Errorf("FEAT-015: Root.Target must be project-relative; got %s in package %s; update the manifest to use a relative path", pkg.Install.Root.Target, pkg.Name)
32		}
33	
34		// Switch into projectRoot so relative install targets resolve against the
35		// project, not the caller's cwd. This keeps copyMapping, ExpandHome, and
36		// the recorded entry.Files paths project-relative.
37		if projectRoot != "" {
38			absProject, absErr := filepath.Abs(projectRoot)
39			if absErr == nil {
40				if origDir, gwdErr := os.Getwd(); gwdErr == nil && origDir != absProject {
41					if err := os.Chdir(absProject); err == nil {
42						defer func() { _ = os.Chdir(origDir) }()
43					}
44				}
45			}
46		}
47	
48		// Download and extract the release tarball to a temp directory.
49		tmpDir, err := os.MkdirTemp("", "ddx-install-"+pkg.Name+"-*")
50		if err != nil {
51			return entry, fmt.Errorf("creating temp dir: %w", err)
52		}
53		defer func() { _ = os.RemoveAll(tmpDir) }()
54	
55		tarballURL := githubTarballURL(pkg.Source, pkg.Version)
56		extractedDir, err := downloadAndExtract(tarballURL, tmpDir)
57		if err != nil {
58			return entry, fmt.Errorf("downloading %s: %w", tarballURL, err)
59		}
60	
61		if manifestPkg, manifestMissing, manifestIssues, manifestErr := LoadPackageManifestWithFallback(extractedDir, pkg); manifestErr == nil || (os.IsNotExist(manifestErr) && manifestMissing) {
62			if manifestPkg != nil {
63				pkg = manifestPkg
64			}
65		} else {
66			if len(manifestIssues) > 0 {
67				return entry, fmt.Errorf("validating package manifest: %s", JoinValidationIssues(manifestIssues))
68			}
69			return entry, fmt.Errorf("loading package manifest: %w", manifestErr)
70		}
71	
72		if pkg.Install.Root == nil {
73			pkg.Install.Root = &InstallMapping{
74				Source: ".",
75				Target: defaultPackageRootTarget(pkg.Name),
76			}
77		}
78	
79		// FEAT-015: plugin install targets must be project-relative. Manifests
80		// that try to write into the user's home are rejected so plugins can't
81		// pollute global state.
82		if strings.HasPrefix(pkg.Install.Root.Target, "~") {
83			return entry, fmt.Errorf("FEAT-015: Root.Target must be project-relative; got %s in package %s; update the manifest to use a relative path", pkg.Install.Root.Target, pkg.Name)
84		}
85	
86		if issues := ValidatePackageStructure(extractedDir, pkg); len(issues) > 0 {
87			return entry, fmt.Errorf("validating package structure: %s", JoinValidationIssues(issues))
88		}
89	
90		// Process Root mapping — copy the plugin tree into the project-local
91		// install location (e.g. .ddx/plugins/<name>/).
92		var installedRoot string
93		files, err := copyMapping(extractedDir, pkg.Install.Root)
94		if err != nil {
95			return entry, fmt.Errorf("installing plugin root: %w", err)
96		}
97		entry.Files = append(entry.Files, files...)
98		installedRoot = ExpandHome(pkg.Install.Root.Target)
99	
100		// Ensure declared executables have the execute bit set.
101		for _, rel := range pkg.Install.Executable {
102			p := filepath.Join(installedRoot, filepath.FromSlash(rel))
103			if info, err := os.Stat(p); err == nil && !info.IsDir() {
104				_ = os.Chmod(p, info.Mode()|0111)
105			}
106		}
107	
108		// Process Skills via the manifest mappings. Each mapping copies real files
109		// into its declared target. No symlinks are ever created -- this is the
110		// cross-platform invariant that FEAT-015 relies on.
111		if len(pkg.Install.Skills) > 0 {
112			written, err := installMappings(extractedDir, pkg.Install.Skills)
113			if err != nil {
114				return entry, fmt.Errorf("installing skills: %w", err)
115			}
116			entry.Files = append(entry.Files, written...)
117		}
118	
119		// Process Scripts mapping — copy the script to the target path.
120		// If the target is already a symlink, the developer is managing it
121		// themselves (e.g. symlink to their git checkout) — skip with a notice.
122		if pkg.Install.Scripts != nil {
123			dst := ExpandHome(pkg.Install.Scripts.Target)
124			if li, err := os.Lstat(dst); err == nil && li.Mode()&os.ModeSymlink != 0 {
125				target, _ := os.Readlink(dst)
126				fmt.Fprintf(os.Stderr, "notice: %s is a symlink → %s (developer mode, skipping copy)\n", dst, target)
127				entry.Files = append(entry.Files, dst)
128			} else {
129				srcDir := extractedDir
130				if installedRoot != "" {
131					srcDir = installedRoot
132				}
133				files, err := copyMapping(srcDir, pkg.Install.Scripts)
134				if err != nil {
135					return entry, fmt.Errorf("installing scripts: %w", err)
136				}
137				entry.Files = append(entry.Files, files...)
138	
139				// Ensure the installed script is executable.
140				if info, err := os.Stat(dst); err == nil && !info.IsDir() {
141					_ = os.Chmod(dst, info.Mode()|0111)
142				}
143			}
144		}
145	
146		// Process symlinks.
147		for _, sym := range pkg.Install.Symlinks {
148			src := ExpandHome(sym.Source)
149			dst := ExpandHome(sym.Target)
150	
151			// Create parent dir if needed.
152			if err := os.MkdirAll(filepath.Dir(dst), 0755); err != nil {
153				return entry, fmt.Errorf("creating symlink dir %s: %w", filepath.Dir(dst), err)
154			}
155	
156			// Remove existing symlink/file if present.
157			if _, err := os.Lstat(dst); err == nil {
158				if err := os.RemoveAll(dst); err != nil {
159					return entry, fmt.Errorf("removing existing %s: %w", dst, err)
160				}
161			}
162	
163			if err := os.Symlink(src, dst); err != nil {
164				return entry, fmt.Errorf("creating symlink %s -> %s: %w", dst, src, err)
165			}
166			entry.Files = append(entry.Files, dst)
167		}
168	
169		return entry, nil
170	}
