172	// installMappings applies each mapping relative to srcDir and returns the
173	// project-relative files written by those mappings.
174	func installMappings(srcDir string, mappings []InstallMapping) ([]string, error) {
175		var written []string
176		for _, mapping := range mappings {
177			files, err := copyMapping(srcDir, &mapping)
178			if err != nil {
179				return nil, fmt.Errorf("copy %q -> %q: %w", mapping.Source, mapping.Target, err)
180			}
181			written = append(written, files...)
182		}
183		return written, nil
184	}
