186	// InstallResource installs a single resource file (e.g. "persona/strict-code-reviewer")
187	// from the ddx-library GitHub repo into the local .ddx/plugins/ddx/<type>/ directory.
188	func InstallResource(resourcePath string) (InstalledEntry, error) {
189		entry := InstalledEntry{
190			Name:        resourcePath,
191			Version:     "latest",
192			Type:        PackageTypeResource,
193			Source:      "https://github.com/DocumentDrivenDX/ddx-library",
194			InstalledAt: time.Now(),
195		}
196	
197		// resourcePath is like "persona/strict-code-reviewer"
198		parts := strings.SplitN(resourcePath, "/", 2)
199		if len(parts) != 2 {
200			return entry, fmt.Errorf("invalid resource path %q: expected <type>/<name>", resourcePath)
201		}
202		resourceType, resourceName := parts[0], parts[1]
203	
204		// Determine target directory relative to cwd.
205		target := filepath.Join(".ddx", "plugins", "ddx", resourceType+"s")
206		if err := os.MkdirAll(target, 0755); err != nil {
207			return entry, fmt.Errorf("creating target directory %s: %w", target, err)
208		}
209	
210		// Fetch raw file from GitHub.
211		rawURL := fmt.Sprintf(
212			"https://raw.githubusercontent.com/easel/ddx-library/main/%ss/%s.md",
213			resourceType, resourceName,
214		)
215	
216		destFile := filepath.Join(target, resourceName+".md")
217		if err := downloadFile(rawURL, destFile); err != nil {
218			return entry, fmt.Errorf("downloading %s: %w", rawURL, err)
219		}
220	
221		entry.Files = append(entry.Files, destFile)
222		return entry, nil
223	}
