225	// UninstallPackage removes files recorded in the entry.
226	func UninstallPackage(entry *InstalledEntry) error {
227		var errs []string
228		for _, f := range entry.Files {
229			expanded := ExpandHome(f)
230			if err := os.Remove(expanded); err != nil && !os.IsNotExist(err) {
231				errs = append(errs, fmt.Sprintf("removing %s: %v", f, err))
232			}
233		}
234		if len(errs) > 0 {
235			return fmt.Errorf("uninstall errors: %s", strings.Join(errs, "; "))
236		}
237		return nil
238	}
