240	// githubTarballURL builds a GitHub release tarball URL from a repo URL and version tag.
241	// e.g. "https://github.com/owner/repo" + "1.0.0" →
242	//
243	//	"https://github.com/owner/repo/archive/refs/tags/v1.0.0.tar.gz"
244	func githubTarballURL(repoURL, version string) string {
245		tag := version
246		if !strings.HasPrefix(tag, "v") {
247			tag = "v" + tag
248		}
249		return strings.TrimRight(repoURL, "/") + "/archive/refs/tags/" + tag + ".tar.gz"
250	}
