252	// downloadAndExtract downloads a .tar.gz from url into destDir and returns
253	// the path of the single top-level directory extracted from the archive.
254	func downloadAndExtract(url, destDir string) (string, error) {
255		resp, err := http.Get(url) //nolint:noctx
256		if err != nil {
257			return "", fmt.Errorf("fetching %s: %w", url, err)
258		}
259		defer func() { _ = resp.Body.Close() }()
260	
261		if resp.StatusCode != http.StatusOK {
262			return "", fmt.Errorf("fetching %s: HTTP %s", url, resp.Status)
263		}
264	
265		gz, err := gzip.NewReader(resp.Body)
266		if err != nil {
267			return "", fmt.Errorf("reading gzip: %w", err)
268		}
269		defer func() { _ = gz.Close() }()
270	
271		tr := tar.NewReader(gz)
272		var topDir string
273	
274		for {
275			hdr, err := tr.Next()
276			if err == io.EOF {
277				break
278			}
279			if err != nil {
280				return "", fmt.Errorf("reading tar: %w", err)
281			}
282	
283			// Sanitize path to prevent directory traversal.
284			clean := filepath.Clean(hdr.Name)
285			if strings.HasPrefix(clean, "..") {
286				continue
287			}
288	
289			dest := filepath.Join(destDir, clean)
290	
291			// Skip PAX global headers (GitHub tarballs include these).
292			if hdr.Typeflag == tar.TypeXGlobalHeader {
293				continue
294			}
295	
296			// Track the top-level directory name.
297			parts := strings.SplitN(clean, string(filepath.Separator), 2)
298			if topDir == "" && parts[0] != "" && parts[0] != "." {
299				topDir = parts[0]
300			}
301	
302			switch hdr.Typeflag {
303			case tar.TypeDir:
304				if err := os.MkdirAll(dest, 0755); err != nil {
305					return "", err
306				}
307			case tar.TypeReg:
308				if err := os.MkdirAll(filepath.Dir(dest), 0755); err != nil {
309					return "", err
310				}
311				f, err := os.OpenFile(dest, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, hdr.FileInfo().Mode())
312				if err != nil {
313					return "", err
314				}
315				if _, err := io.Copy(f, tr); err != nil {
316					_ = f.Close()
317					return "", err
318				}
319				_ = f.Close()
320			case tar.TypeSymlink:
321				if err := os.MkdirAll(filepath.Dir(dest), 0755); err != nil {
322					return "", err
323				}
324				_ = os.Remove(dest)
325				if err := os.Symlink(hdr.Linkname, dest); err != nil {
326					return "", err
327				}
328			}
329		}
330	
331		if topDir == "" {
332			return destDir, nil
333		}
334		return filepath.Join(destDir, topDir), nil
335	}
