337	// CopyScriptFromRoot copies a script from an installed plugin root to the
338	// target path. Exported for use by local install path.
339	func CopyScriptFromRoot(installedRoot string, mapping *InstallMapping) (string, error) {
340		files, err := copyMapping(installedRoot, mapping)
341		if err != nil {
342			return "", err
343		}
344		dst := ExpandHome(mapping.Target)
345		if info, err := os.Stat(dst); err == nil && !info.IsDir() {
346			_ = os.Chmod(dst, info.Mode()|0111)
347		}
348		if len(files) > 0 {
349			return files[0], nil
350		}
351		return dst, nil
352	}
