354	// copyMapping copies files from srcDir/<mapping.Source> to ExpandHome(mapping.Target).
355	// If the source is a single file and the target does not end with a path
356	// separator, the target is treated as the exact destination file path.
357	// If the source is a directory (or target ends with /), files are copied
358	// into the target directory.
359	// Returns the list of destination files written.
360	func copyMapping(srcDir string, mapping *InstallMapping) ([]string, error) {
361		src := filepath.Join(srcDir, filepath.FromSlash(mapping.Source))
362		dst := ExpandHome(mapping.Target)
363	
364		info, err := os.Stat(src)
365		if os.IsNotExist(err) {
366			// Source path doesn't exist in this repo — skip silently.
367			return nil, nil
368		}
369		if err != nil {
370			return nil, err
371		}
372	
373		var written []string
374	
375		if info.IsDir() {
376			// If dst is an existing symlink (e.g. from a prior --local install),
377			// remove it before creating the real directory.
378			if li, err := os.Lstat(dst); err == nil && li.Mode()&os.ModeSymlink != 0 {
379				if err := os.Remove(dst); err != nil {
380					return nil, fmt.Errorf("removing symlink at %s: %w", dst, err)
381				}
382			}
383	
384			// Copy directory tree into dst (create dst as a directory).
385			if err := os.MkdirAll(dst, 0755); err != nil {
386				return nil, fmt.Errorf("creating target dir %s: %w", dst, err)
387			}
388	
389			// HELIX skills use symlinks, so resolve each entry via os.Stat.
390			entries, err := os.ReadDir(src)
391			if err != nil {
392				return nil, err
393			}
394			for _, e := range entries {
395				srcPath := filepath.Join(src, e.Name())
396				dstPath := filepath.Join(dst, e.Name())
397	
398				fi, err := os.Stat(srcPath)
399				if err != nil {
400					continue // skip broken symlinks
401				}
402	
403				if fi.IsDir() {
404					subFiles, subErr := copyMapping(srcPath, &InstallMapping{Source: ".", Target: dstPath})
405					if subErr != nil {
406						return nil, subErr
407					}
408					written = append(written, subFiles...)
409				} else if fi.Mode().IsRegular() {
410					if err := copyFile(srcPath, dstPath); err != nil {
411						return nil, err
412					}
413					written = append(written, dstPath)
414				}
415			}
416		} else {
417			// Source is a single file. If target ends with /, copy into that
418			// directory using the source filename; otherwise treat target as
419			// the exact destination file path.
420			var dstFile string
421			if strings.HasSuffix(mapping.Target, "/") {
422				if err := os.MkdirAll(dst, 0755); err != nil {
423					return nil, fmt.Errorf("creating target dir %s: %w", dst, err)
424				}
425				dstFile = filepath.Join(dst, filepath.Base(src))
426			} else {
427				dstFile = dst
428			}
429			if err := copyFile(src, dstFile); err != nil {
430				return nil, err
431			}
432			written = append(written, dstFile)
433		}
434	
435		return written, nil
436	}
437	
438	// copyFile copies src to dst, creating parent directories as needed.
439	// Preserves the source file's permissions. If dst already exists (file,
440	// symlink, or directory), it is removed first.
441	func copyFile(src, dst string) error {
442		if err := os.MkdirAll(filepath.Dir(dst), 0755); err != nil {
443			return err
444		}
445	
446		// Remove any existing file/symlink/directory at dst.
447		if _, err := os.Lstat(dst); err == nil {
448			if err := os.RemoveAll(dst); err != nil {
449				return fmt.Errorf("removing existing %s: %w", dst, err)
450			}
451		}
452	
453		srcInfo, err := os.Stat(src)
454		if err != nil {
455			return err
456		}
457	
458		in, err := os.Open(src)
459		if err != nil {
460			return err
461		}
462		defer func() { _ = in.Close() }()
463	
464		out, err := os.OpenFile(dst, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, srcInfo.Mode())
465		if err != nil {
466			return err
467		}
468		defer func() { _ = out.Close() }()
469	
470		_, err = io.Copy(out, in)
471		return err
472	}
473	
474	// downloadFile fetches url and writes it to dest.
475	func downloadFile(url, dest string) error {
476		resp, err := http.Get(url) //nolint:noctx
477		if err != nil {
478			return fmt.Errorf("fetching %s: %w", url, err)
479		}
480		defer func() { _ = resp.Body.Close() }()
481	
482		if resp.StatusCode != http.StatusOK {
483			return fmt.Errorf("fetching %s: HTTP %s", url, resp.Status)
484		}
485	
486		f, err := os.Create(dest)
487		if err != nil {
488			return err
489		}
490		defer func() { _ = f.Close() }()
491	
492		_, err = io.Copy(f, resp.Body)
493		return err
494	}
495	
496	// ExpandHome expands a leading ~ to the user's home directory.
497	func ExpandHome(path string) string {
498		if !strings.HasPrefix(path, "~") {
499			return path
500		}
501		home, err := os.UserHomeDir()
502		if err != nil {
503			return path
504		}
505		return filepath.Join(home, path[1:])
506	}
