131	// Search returns all packages whose name, description, or keywords contain the query.
132	func (r *Registry) Search(query string) []Package {
133		q := strings.ToLower(query)
134		var results []Package
135		for _, pkg := range r.Packages {
136			if matchesQuery(pkg, q) {
137				results = append(results, pkg)
138			}
139		}
140		return results
141	}
142	
143	func matchesQuery(pkg Package, query string) bool {
144		if strings.Contains(strings.ToLower(pkg.Name), query) {
145			return true
146		}
147		if strings.Contains(strings.ToLower(pkg.Description), query) {
148			return true
149		}
150		if strings.Contains(strings.ToLower(string(pkg.Type)), query) {
151			return true
152		}
153		for _, kw := range pkg.Keywords {
154			if strings.Contains(strings.ToLower(kw), query) {
155				return true
156			}
157		}
158		return false
159	}
