235	func prepareSymlinkTarget(target string, force bool) error {
236		if info, err := os.Lstat(target); err == nil {
237			if info.Mode()&os.ModeSymlink != 0 || force {
238				if err := os.RemoveAll(target); err != nil {
239					return fmt.Errorf("removing existing %s: %w", target, err)
240				}
241				return nil
242			}
243			return fmt.Errorf("%s already exists (use --force to replace)", target)
244		} else if !os.IsNotExist(err) {
245			return fmt.Errorf("checking existing %s: %w", target, err)
246		}
247		return nil
248	}
