250	// installLocal installs a plugin from a local directory into the current
251	// checkout as a developer overlay. It intentionally does not update installed
252	// state and does not auto-commit: the recorded plugin pin remains whatever the
253	// project already declares, while this machine can test a local plugin tree.
254	func (f *CommandFactory) installLocal(name, localPath string, force bool, out io.Writer) error {
255		// Resolve to absolute path.
256		absPath, err := filepath.Abs(localPath)
257		if err != nil {
258			return fmt.Errorf("resolving path %s: %w", localPath, err)
259		}
260		if _, err := os.Stat(absPath); os.IsNotExist(err) {
261			return fmt.Errorf("local path does not exist: %s", absPath)
262		}
263	
264		// Load package.yaml when present so local installs honor the manifest
265		// contract, but keep the built-in registry as a compatibility fallback.
266		reg := registry.BuiltinRegistry()
267		fallbackPkg, _ := reg.Find(name)
268	
269		pkg, manifestMissing, manifestIssues, manifestErr := registry.LoadPackageManifestWithFallback(absPath, fallbackPkg)
270		if manifestErr == nil {
271			if strings.TrimSpace(pkg.Name) != "" && pkg.Name != name {
272				return fmt.Errorf("local package name %q does not match package.yaml name %q", name, pkg.Name)
273			}
274		} else {
275			if os.IsNotExist(manifestErr) && manifestMissing {
276				if pkg == nil {
277					pkg = &registry.Package{
278						Name:        name,
279						Version:     "local",
280						Description: "local plugin package",
281						Type:        registry.PackageTypePlugin,
282						Source:      absPath,
283					}
284				}
285			} else if len(manifestIssues) > 0 {
286				return fmt.Errorf("validating package manifest: %w", manifestErr)
287			} else {
288				return fmt.Errorf("loading package manifest: %w", manifestErr)
289			}
290		}
291	
292		if pkg == nil {
293			pkg = &registry.Package{
294				Name:        name,
295				Version:     "local",
296				Description: "local plugin package",
297				Type:        registry.PackageTypePlugin,
298				Source:      absPath,
299			}
300		}
301	
302		if pkg.Install.Root == nil {
303			pkg.Install.Root = &registry.InstallMapping{
304				Source: ".",
305				Target: fmt.Sprintf(".ddx/plugins/%s", pkg.Name),
306			}
307		}
308		if len(pkg.Install.Skills) == 0 && localPluginHasSkills(absPath) {
309			pkg.Install.Skills = []registry.InstallMapping{
310				{Source: "skills/", Target: ".agents/skills/"},
311			}
312		}
313	
314		if strings.HasPrefix(pkg.Install.Root.Target, "~") {
315			return fmt.Errorf("FEAT-015: Root.Target must be project-relative; got %s in package %s; update the manifest to use a relative path", pkg.Install.Root.Target, pkg.Name)
316		}
317	
318		projectRoot := f.WorkingDir
319		if projectRoot == "" {
320			projectRoot, _ = os.Getwd()
321		}
322		var oldFiles []string
323		if state, err := registry.LoadState(); err == nil {
324			if old := state.FindInstalled(pkg.Name); old != nil {
325				oldFiles = append([]string{}, old.Files...)
326				_, _ = markLocalInstallOverlay(projectRoot, pkg.Name, oldFiles)
327			}
328		}
329	
330		if issues := filterLocalInstallValidationIssues(absPath, registry.ValidatePackageStructure(absPath, pkg)); len(issues) > 0 {
331			return fmt.Errorf("validating package structure: %s", registry.JoinValidationIssues(issues))
332		}
333	
334		pluginDir := pkg.Install.Root.Target
335	
336		if err := prepareSymlinkTarget(pluginDir, force); err != nil {
337			return err
338		}
339	
340		if err := os.MkdirAll(filepath.Dir(pluginDir), 0755); err != nil {
341			return fmt.Errorf("creating plugins dir: %w", err)
342		}
343	
344		if err := os.Symlink(absPath, pluginDir); err != nil {
345			return fmt.Errorf("linking plugin into %s: %w", pluginDir, err)
346		}
347	
348		fmt.Fprintf(out, "Linked %s -> %s\n", pluginDir, absPath)
349	
350		entry := registry.InstalledEntry{
351			Name:    pkg.Name,
352			Version: pkg.Version,
353			Type:    pkg.Type,
354			Source:  absPath,
355		}
356		entry.Files = append(entry.Files, pluginDir)
357	
358		// Install local skills as symlinks into each supported harness surface.
359		if len(pkg.Install.Skills) > 0 {
360			absProject := f.WorkingDir
361			if absProject == "" {
362				absProject, _ = os.Getwd()
363			}
364			if !filepath.IsAbs(absProject) {
365				absProject, _ = filepath.Abs(absProject)
366			}
367			writtenSkills, err := installLocalSkillSymlinks(absPath, absProject, force)
368			if err != nil {
369				return fmt.Errorf("installing skills: %w", err)
370			}
371			entry.Files = append(entry.Files, writtenSkills...)
372		}
373	
374		// Copy CLI script if defined (skip if target is a developer symlink).
375		if pkg.Install.Scripts != nil {
376			dst := registry.ExpandHome(pkg.Install.Scripts.Target)
377			if li, lErr := os.Lstat(dst); lErr == nil && li.Mode()&os.ModeSymlink != 0 {
378				target, _ := os.Readlink(dst)
379				fmt.Fprintf(out, "notice: %s is a symlink → %s (developer mode, skipping copy)\n", dst, target)
380				entry.Files = append(entry.Files, dst)
381			} else {
382				copied, err := registry.CopyScriptFromRoot(pluginDir, pkg.Install.Scripts)
383				if err != nil {
384					fmt.Fprintf(out, "Warning: script copy error: %v\n", err)
385				} else {
386					entry.Files = append(entry.Files, copied)
387				}
388			}
389		}
390	
391		// Set execute bits on installed plugin files.
392		for _, rel := range pkg.Install.Executable {
393			p := filepath.Join(pluginDir, filepath.FromSlash(rel))
394			if info, err := os.Stat(p); err == nil && !info.IsDir() {
395				_ = os.Chmod(p, info.Mode()|0111)
396			}
397		}
398	
399		entry.InstalledAt = time.Now()
400	
401		removed := removeStaleFilesFromInstall(oldFiles, entry.Files)
402		if removed > 0 {
403			fmt.Fprintf(out, "Removed %d stale file(s) from previous install\n", removed)
404		}
405	
406		if hidden, err := markLocalInstallOverlay(projectRoot, entry.Name, entry.Files); err != nil {
407			fmt.Fprintf(out, "Warning: local install is active but git overlay hiding failed: %v\n", err)
408		} else if hidden > 0 {
409			fmt.Fprintf(out, "Marked %d tracked local overlay file(s) skip-worktree\n", hidden)
410		}
411	
412		fmt.Fprintf(out, "Installed %s from local path %s — %d file(s); recorded plugin pin unchanged\n", entry.Name, absPath, len(entry.Files))
413		return nil
414	}
415	
416	func markLocalInstallOverlay(projectRoot, pluginName string, files []string) (int, error) {
417		if projectRoot == "" {
418			return 0, nil
419		}
420	
421		ctx := context.Background()
422		topOut, err := internalgit.Command(ctx, projectRoot, "rev-parse", "--show-toplevel").Output()
423		if err != nil {
424			return 0, nil
425		}
426		repoRoot := strings.TrimSpace(string(topOut))
427		if repoRoot == "" {
428			return 0, nil
429		}
430	
431		paths := localOverlayPaths(pluginName, files)
432		if len(paths) == 0 {
433			return 0, nil
434		}
435		if err := addLocalOverlayIgnores(repoRoot, paths); err != nil {
436			return 0, err
437		}
438	
439		args := append([]string{"ls-files", "-z", "--"}, paths...)
440		trackedOut, err := internalgit.Command(ctx, repoRoot, args...).Output()
441		if err != nil {
442			return 0, err
443		}
444		var tracked []string
445		for _, p := range strings.Split(string(trackedOut), "\x00") {
446			if p != "" {
447				tracked = append(tracked, p)
448			}
449		}
450		for start := 0; start < len(tracked); start += 100 {
451			end := start + 100
452			if end > len(tracked) {
453				end = len(tracked)
454			}
455			args := append([]string{"update-index", "--skip-worktree", "--"}, tracked[start:end]...)
456			if err := internalgit.Command(ctx, repoRoot, args...).Run(); err != nil {
457				return 0, err
458			}
459		}
460		return len(tracked), nil
461	}
