463	func localPluginHasSkills(root string) bool {
464		for _, candidate := range []string{
465			filepath.Join(root, ".agents", "skills"),
466			filepath.Join(root, "skills"),
467		} {
468			if info, err := os.Stat(candidate); err == nil && info.IsDir() {
469				return true
470			}
471		}
472		return false
473	}
474	
475	func localOverlayPaths(pluginName string, files []string) []string {
476		seen := map[string]bool{}
477		add := func(path string) {
478			path = filepath.ToSlash(strings.TrimSpace(path))
479			path = strings.TrimPrefix(path, "./")
480			if path == "" || strings.HasPrefix(path, "~") || filepath.IsAbs(path) {
481				return
482			}
483			if !seen[path] {
484				seen[path] = true
485			}
486		}
487	
488		add(filepath.ToSlash(filepath.Join(".ddx", "plugins", pluginName)))
489		for _, file := range files {
490			p := filepath.ToSlash(file)
491			for _, prefix := range []string{".agents/skills/", ".claude/skills/"} {
492				if strings.HasPrefix(p, prefix) {
493					rest := strings.TrimPrefix(p, prefix)
494					name := strings.Split(rest, "/")[0]
495					if name != "" {
496						add(prefix + name)
497					}
498				}
499			}
500		}
501	
502		paths := make([]string, 0, len(seen))
503		for p := range seen {
504			paths = append(paths, p)
505		}
506		sort.Strings(paths)
507		return paths
508	}
