550	func localSkillSourceEntries(pluginRoot string) (string, []os.DirEntry, error) {
551		for _, candidate := range []string{
552			filepath.Join(pluginRoot, ".agents", "skills"),
553			filepath.Join(pluginRoot, "skills"),
554		} {
555			entries, err := os.ReadDir(candidate)
556			if err == nil && len(entries) > 0 {
557				return candidate, entries, nil
558			}
559			if err != nil && !os.IsNotExist(err) {
560				return "", nil, err
561			}
562		}
563		return "", nil, nil
564	}
