566	func addLocalOverlayIgnores(repoRoot string, paths []string) error {
567		excludePath := filepath.Join(repoRoot, ".git", "info", "exclude")
568		existing, _ := os.ReadFile(excludePath)
569		text := string(existing)
570	
571		var additions []string
572		for _, p := range paths {
573			pattern := filepath.ToSlash(p)
574			if !strings.HasSuffix(pattern, "/") {
575				pattern += "/"
576			}
577			if !strings.Contains(text, "\n"+pattern+"\n") && !strings.HasPrefix(text, pattern+"\n") {
578				additions = append(additions, pattern)
579			}
580		}
581		if len(additions) == 0 {
582			return nil
583		}
584	
585		var sb strings.Builder
586		if len(existing) > 0 && !strings.HasSuffix(text, "\n") {
587			sb.WriteString("\n")
588		}
589		if !strings.Contains(text, "# DDx local plugin overlays") {
590			sb.WriteString("\n# DDx local plugin overlays\n")
591		}
592		for _, pattern := range additions {
593			sb.WriteString(pattern)
594			sb.WriteString("\n")
595		}
596		return os.WriteFile(excludePath, append(existing, []byte(sb.String())...), 0o644)
597	}
