599	// copyDirTree copies the source directory tree into dst as real files,
600	// returning the list of written file paths (relative to cwd).
601	func copyDirTree(src, dst string) ([]string, error) {
602		var written []string
603		err := filepath.Walk(src, func(path string, info os.FileInfo, err error) error {
604			if err != nil {
605				return err
606			}
607			rel, relErr := filepath.Rel(src, path)
608			if relErr != nil {
609				return relErr
610			}
611			if shouldSkipLocalInstallPath(rel, info) {
612				if info.IsDir() {
613					return filepath.SkipDir
614				}
615				return nil
616			}
617			target := filepath.Join(dst, rel)
618			if info.IsDir() {
619				return os.MkdirAll(target, 0o755)
620			}
621			if info.Mode()&os.ModeSymlink != 0 {
622				// Skip plugin-source symlinks — never materialize.
623				return nil
624			}
625			if !info.Mode().IsRegular() {
626				return nil
627			}
628			if err := os.MkdirAll(filepath.Dir(target), 0o755); err != nil {
629				return err
630			}
631			in, err := os.Open(path)
632			if err != nil {
633				return err
634			}
635			defer func() { _ = in.Close() }()
636			out, err := os.OpenFile(target, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, info.Mode())
637			if err != nil {
638				return err
639			}
640			if _, copyErr := io.Copy(out, in); copyErr != nil {
641				_ = out.Close()
642				return copyErr
643			}
644			if err := out.Close(); err != nil {
645				return err
646			}
647			written = append(written, target)
648			return nil
649		})
650		return written, err
651	}
