653	func filterLocalInstallValidationIssues(root string, issues []registry.ValidationIssue) []registry.ValidationIssue {
654		filtered := issues[:0]
655		for _, issue := range issues {
656			rel, err := filepath.Rel(root, issue.Path)
657			if err == nil && shouldSkipLocalInstallIssue(filepath.ToSlash(rel)) {
658				continue
659			}
660			filtered = append(filtered, issue)
661		}
662		return filtered
663	}
664	
665	func shouldSkipLocalInstallIssue(rel string) bool {
666		rel = strings.TrimPrefix(filepath.ToSlash(rel), "./")
667		for _, prefix := range []string{
668			".git/",
669			".ddx/plugins/",
670			".ddx/agent-logs/",
671			".ddx/executions/",
672			".ddx/exec-runs.d/",
673			".ddx/server/",
674			".ddx/tsnet/",
675			".ddx/workers/",
676			"node_modules/",
677			"tmp/",
678			"website/node_modules/",
679			"website/public/",
680			"website/resources/",
681			"website/test-results/",
682			"website/playwright-report/",
683		} {
684			if strings.HasPrefix(rel, prefix) {
685				return true
686			}
687		}
688		return false
689	}
690	
691	func shouldSkipLocalInstallPath(rel string, info os.FileInfo) bool {
692		rel = strings.TrimPrefix(filepath.ToSlash(rel), "./")
693		if rel == "." || rel == "" {
694			return false
695		}
696		if shouldSkipLocalInstallIssue(rel + "/") {
697			return true
698		}
699		if info.IsDir() {
700			base := filepath.Base(rel)
701			return base == ".git" || base == "node_modules" || base == "tmp"
702		}
703		return false
704	}
