717	func (f *CommandFactory) runInstalled(cmd *cobra.Command, args []string) error {
718		out := cmd.OutOrStdout()
719	
720		state, err := registry.LoadState()
721		if err != nil {
722			return fmt.Errorf("loading state: %w", err)
723		}
724	
725		if len(state.Installed) == 0 {
726			fmt.Fprintln(out, "No packages installed.")
727			return nil
728		}
729	
730		w := tabwriter.NewWriter(out, 0, 0, 2, ' ', 0)
731		fmt.Fprintln(w, "NAME\tVERSION\tTYPE\tSTATUS\tINSTALLED")
732		for _, e := range state.Installed {
733			status := "ok"
734			if !e.VerifyFiles() {
735				status = "BROKEN"
736			}
737			fmt.Fprintf(w, "%s\t%s\t%s\t%s\t%s\n",
738				e.Name,
739				e.Version,
740				string(e.Type),
