787	func (f *CommandFactory) newVerifyCommand() *cobra.Command {
788		return &cobra.Command{
789			Use:   "verify",
790			Short: "Verify installed package integrity",
791			Long:  `Check that all files recorded for installed packages still exist and symlinks resolve correctly.`,
792			Args:  cobra.NoArgs,
793			RunE:  f.runVerify,
794		}
795	}
796	
797	func (f *CommandFactory) runVerify(cmd *cobra.Command, args []string) error {
798		out := cmd.OutOrStdout()
799	
800		state, err := registry.LoadState()
801		if err != nil {
802			return fmt.Errorf("loading state: %w", err)
803		}
804	
805		if len(state.Installed) == 0 {
806			fmt.Fprintln(out, "No packages installed.")
807			return nil
808		}
809	
810		var totalIssues int
811		for _, entry := range state.Installed {
812			var issues []string
813			for _, f := range entry.Files {
814				expanded := registry.ExpandHome(f)
815				info, err := os.Lstat(expanded)
816				if os.IsNotExist(err) {
817					issues = append(issues, fmt.Sprintf("  missing: %s", f))
818					continue
819				}
820				if err != nil {
821					issues = append(issues, fmt.Sprintf("  error: %s: %v", f, err))
822					continue
823				}
824				// Check symlinks resolve.
825				if info.Mode()&os.ModeSymlink != 0 {
826					target, err := os.Readlink(expanded)
827					if err != nil {
828						issues = append(issues, fmt.Sprintf("  broken symlink: %s", f))
829						continue
830					}
831					// Resolve relative symlinks against their parent directory.
832					if !filepath.IsAbs(target) {
833						target = filepath.Join(filepath.Dir(expanded), target)
834					}
835					if _, err := os.Stat(target); os.IsNotExist(err) {
836						issues = append(issues, fmt.Sprintf("  broken symlink: %s -> %s", f, target))
837					}
838				}
839			}
840	
841			if len(issues) == 0 {
842				fmt.Fprintf(out, "%s %s: OK (%d files)\n", entry.Name, entry.Version, len(entry.Files))
843			} else {
844				fmt.Fprintf(out, "%s %s: %d issue(s)\n", entry.Name, entry.Version, len(issues))
845				for _, issue := range issues {
846					fmt.Fprintln(out, issue)
847				}
848				totalIssues += len(issues)
849			}
850		}
851	
852		if totalIssues > 0 {
853			return fmt.Errorf("%d integrity issue(s) found — run 'ddx install <name> --force' to repair", totalIssues)
854		}
855		return nil
856	}
