13	// AuditInstalledEntry checks one installed package entry for plugin issues.
14	func AuditInstalledEntry(entry InstalledEntry, fallback *Package) []ValidationIssue {
15		var issues []ValidationIssue
16		root := installedRootPath(entry)
17		if root == "" {
18			issues = append(issues, ValidationIssue{Message: fmt.Sprintf("installed entry %q has no recorded plugin root", entry.Name)})
19			return issues
20		}
21	
22		issues = append(issues, auditRecordedFiles(entry)...)
23	
24		manifest, manifestMissing, manifestIssues := loadPackageDefinitionForAudit(root, fallback)
25		issues = append(issues, manifestIssues...)
26	
27		if manifestMissing {
28			issues = append(issues, ValidationIssue{
29				Path:    filepath.Join(root, "package.yaml"),
30				Message: "missing package.yaml",
31			})
32		}
33	
34		if manifest == nil {
35			manifest = &Package{}
36		}
37	
38		issues = append(issues, ValidatePackageStructure(root, manifest)...)
39		return issues
40	}
41	
42	// ValidatePackageStructure checks the skill, symlink, and executable layout
43	// for a package root before install or after install-state recovery.
44	func ValidatePackageStructure(root string, pkg *Package) []ValidationIssue {
45		if pkg == nil {
46			return []ValidationIssue{{Path: filepath.Join(root, "package.yaml"), Message: "missing package definition"}}
47		}
48		return auditPluginRoot(root, pkg)
49	}
50	
51	func loadPackageDefinitionForAudit(root string, fallback *Package) (*Package, bool, []ValidationIssue) {
52		manifest, manifestMissing, issues, err := LoadPackageManifestWithFallback(root, fallback)
53		if err == nil || os.IsNotExist(err) {
54			// Report validation issues even when package is valid, so audit shows schema problems.
55			return manifest, manifestMissing, issues
56		}
57	
58		// If a partial package was returned (YAML parsed but validation issues exist),
59		// return it with the issues so structural audits can proceed.
60		if manifest != nil {
61			return manifest, false, issues
62		}
63	
64		if len(issues) == 0 {
65			issues = append(issues, ValidationIssue{Path: filepath.Join(root, "package.yaml"), Message: err.Error()})
66		}
67		return manifest, false, issues
68	}
69	
70	func auditPluginRoot(root string, pkg *Package) []ValidationIssue {
71		var issues []ValidationIssue
72	
73		if pkg.APIVersion != "" && pkg.APIVersion != SupportedPackageAPIVersion {
74			issues = append(issues, ValidationIssue{
75				Path:    filepath.Join(root, "package.yaml"),
76				Message: fmt.Sprintf("unsupported `api_version` %q (supported: %s)", pkg.APIVersion, SupportedPackageAPIVersion),
77			})
78		}
79	
80		ignoredBrokenSymlinkPaths := collectIgnoredBrokenSymlinkPaths(root, pkg)
81		for _, symlinkIssue := range auditBrokenSymlinks(root, ignoredBrokenSymlinkPaths) {
82			issues = append(issues, symlinkIssue)
83		}
84	
85		for _, skillRoot := range collectSkillRoots(root, pkg) {
86			issues = append(issues, auditSkillRoot(root, skillRoot)...)
87		}
88	
89		for _, rel := range pkg.Install.Executable {
90			issues = append(issues, auditExecutable(root, rel)...)
91		}
92	
93		return issues
94	}
