96	func auditRecordedFiles(entry InstalledEntry) []ValidationIssue {
97		var issues []ValidationIssue
98		seen := map[string]bool{}
99		recordedPaths := append([]string(nil), entry.Files...)
100		if root := installedRootPath(entry); root != "" {
101			recordedPaths = append(recordedPaths, root)
102		}
103		for _, recorded := range recordedPaths {
104			path := ExpandHome(recorded)
105			if path == "" || seen[path] {
106				continue
107			}
108			seen[path] = true
109			info, err := os.Lstat(path)
110			if err != nil {
111				if os.IsNotExist(err) {
112					// Pre-migration entries whose paths begin with ~ are outside the
113					// project root; treat missing paths as no-op (no issue raised).
114					if strings.HasPrefix(recorded, "~") {
115						continue
116					}
117					issues = append(issues, ValidationIssue{Path: path, Message: "missing recorded file or symlink"})
118					continue
119				}
120				issues = append(issues, ValidationIssue{Path: path, Message: err.Error()})
121				continue
122			}
123			if info.Mode()&os.ModeSymlink == 0 {
124				continue
125			}
126	
127			target, err := os.Readlink(path)
128			if err != nil {
129				issues = append(issues, ValidationIssue{Path: path, Message: fmt.Sprintf("broken symlink: %v", err)})
130				continue
131			}
132			if !filepath.IsAbs(target) {
133				target = filepath.Join(filepath.Dir(path), target)
134			}
135			if _, err := os.Stat(target); err != nil {
136				issues = append(issues, ValidationIssue{Path: path, Message: fmt.Sprintf("broken symlink target %q: %v", target, err)})
137			}
138		}
139		return issues
140	}
141	
142	func auditBrokenSymlinks(root string, ignored map[string]bool) []ValidationIssue {
143		var issues []ValidationIssue
144		walkRoot := root
145		if resolved, err := filepath.EvalSymlinks(root); err == nil && resolved != "" {
146			walkRoot = resolved
147		}
148	
149		_ = filepath.WalkDir(walkRoot, func(path string, d fs.DirEntry, err error) error {
150			if err != nil {
151				issues = append(issues, ValidationIssue{Path: path, Message: err.Error()})
152				return nil
153			}
154			if path == walkRoot {
155				return nil
156			}
157	
158			info, err := os.Lstat(path)
159			if err != nil {
160				if os.IsNotExist(err) {
161					issues = append(issues, ValidationIssue{Path: path, Message: "missing installed file"})
162					return nil
163				}
164				issues = append(issues, ValidationIssue{Path: path, Message: err.Error()})
165				return nil
166			}
167			if info.Mode()&os.ModeSymlink == 0 {
168				return nil
169			}
170			if ignored != nil && ignored[path] {
171				return nil
172			}
173	
174			target, err := os.Readlink(path)
175			if err != nil {
176				issues = append(issues, ValidationIssue{Path: path, Message: fmt.Sprintf("broken symlink: %v", err)})
177				return nil
178			}
179			if !filepath.IsAbs(target) {
180				target = filepath.Join(filepath.Dir(path), target)
181			}
182			if _, err := os.Stat(target); err != nil {
183				issues = append(issues, ValidationIssue{Path: path, Message: fmt.Sprintf("broken symlink target %q: %v", target, err)})
184			}
185			return nil
186		})
187	
188		return issues
189	}
190	
191	func collectSkillRoots(root string, pkg *Package) []string {
192		seen := map[string]bool{}
193		var roots []string
194	
195		add := func(candidate string) {
196			if strings.TrimSpace(candidate) == "" {
197				return
198			}
199			abs := candidate
200			if resolved, err := filepath.EvalSymlinks(candidate); err == nil && resolved != "" {
201				abs = resolved
202			} else if resolved, err := filepath.Abs(candidate); err == nil && resolved != "" {
203				abs = resolved
204			}
205			if seen[abs] {
206				return
207			}
208			if _, err := os.Stat(candidate); err != nil {
209				return
210			}
211			seen[abs] = true
212			roots = append(roots, candidate)
213		}
214	
215		for _, mapping := range pkg.Install.Skills {
216			sourceRoot := filepath.Join(root, filepath.FromSlash(mapping.Source))
217			add(sourceRoot)
218	
219			cleanSource := filepath.Clean(filepath.FromSlash(mapping.Source))
220			switch cleanSource {
221			case filepath.Join(".agents", "skills"), filepath.Join(".claude", "skills"):
222				add(filepath.Join(root, "skills"))
223			}
224		}
225	
226		return roots
227	}
228	
229	func collectIgnoredBrokenSymlinkPaths(root string, pkg *Package) map[string]bool {
230		ignored := make(map[string]bool)
231		for _, mapping := range pkg.Install.Skills {
232			cleanSource := filepath.Clean(filepath.FromSlash(mapping.Source))
233			switch cleanSource {
234			case filepath.Join(".agents", "skills"), filepath.Join(".claude", "skills"):
235				skillRoot := filepath.Join(root, cleanSource)
236				entries, err := os.ReadDir(skillRoot)
237				if err != nil {
238					continue
239				}
240				for _, entry := range entries {
241					ignored[filepath.Join(skillRoot, entry.Name())] = true
242				}
243			}
244		}
245		return ignored
246	}
247	
248	func auditSkillRoot(packageRoot, root string) []ValidationIssue {
249		var issues []ValidationIssue
250	
251		info, err := os.Stat(root)
252		if err != nil {
253			issues = append(issues, ValidationIssue{Path: root, Message: err.Error()})
254			return issues
255		}
256		if !info.IsDir() {
257			issues = append(issues, ValidationIssue{Path: root, Message: "expected a skill directory"})
258			return issues
259		}
260	
261		entries, err := os.ReadDir(root)
262		if err != nil {
263			issues = append(issues, ValidationIssue{Path: root, Message: err.Error()})
264			return issues
265		}
266	
267		for _, entry := range entries {
268			skillPath := filepath.Join(root, entry.Name())
269			skillInfo, err := os.Lstat(skillPath)
270			if err != nil {
271				issues = append(issues, ValidationIssue{Path: skillPath, Message: err.Error()})
272				continue
273			}
274			if skillInfo.Mode()&os.ModeSymlink != 0 {
275				if _, err := os.Stat(skillPath); err != nil {
276					if recovered := recoverSkillDir(packageRoot, root, entry.Name()); recovered != "" {
277						skillPath = recovered
278					} else {
279						issues = append(issues, ValidationIssue{Path: skillPath, Message: fmt.Sprintf("broken symlink: %v", err)})
280						continue
281					}
282				}
283			}
284			if !skillInfo.IsDir() && skillInfo.Mode()&os.ModeSymlink == 0 {
285				continue
286			}
287	
288			skillFile := filepath.Join(skillPath, "SKILL.md")
289			data, err := os.ReadFile(skillFile)
290			if err != nil {
291				if os.IsNotExist(err) {
292					issues = append(issues, ValidationIssue{Path: skillPath, Message: "missing SKILL.md"})
293					continue
294				}
295				issues = append(issues, ValidationIssue{Path: skillFile, Message: err.Error()})
296				continue
297			}
298	
299			for _, issue := range skills.ValidateContent(skillFile, data) {
300				issues = append(issues, ValidationIssue{Path: issue.Path, Message: issue.Message})
301			}
302		}
303	
304		return issues
305	}
306	
307	func recoverSkillDir(packageRoot, skillRoot, skillName string) string {
308		candidate := filepath.Join(packageRoot, "skills", skillName)
309		if info, err := os.Stat(candidate); err == nil && info.IsDir() {
310			return candidate
311		}
312	
313		if strings.HasSuffix(filepath.Clean(skillRoot), filepath.Join(".agents", "skills")) ||
314			strings.HasSuffix(filepath.Clean(skillRoot), filepath.Join(".claude", "skills")) {
315			candidate = filepath.Join(packageRoot, "skills", skillName)
316			if info, err := os.Stat(candidate); err == nil && info.IsDir() {
317				return candidate
318			}
319		}
320	
321		return ""
322	}
323	
324	func auditExecutable(root, rel string) []ValidationIssue {
325		path := filepath.Join(root, filepath.FromSlash(rel))
326		info, err := os.Stat(path)
327		if err != nil {
328			return []ValidationIssue{{Path: path, Message: err.Error()}}
329		}
330		if info.IsDir() {
331			return []ValidationIssue{{Path: path, Message: "expected executable file, found directory"}}
332		}
333		if info.Mode()&0111 == 0 {
334			return []ValidationIssue{{Path: path, Message: "file lost execute permission"}}
335		}
336		return nil
337	}
338	
339	func installedRootPath(entry InstalledEntry) string {
340		resolve := func(raw string) string {
341			expanded := ExpandHome(raw)
342			// Pre-migration entries with ~/... paths are outside the project root.
343			// Return empty string so callers skip audit for missing home paths.
344			if strings.HasPrefix(raw, "~") {
345				if _, err := os.Stat(expanded); err != nil {
346					return ""
347				}
348			}
349			return expanded
350		}
351		if len(entry.Files) > 0 {
352			return resolve(entry.Files[0])
353		}
354		if strings.TrimSpace(entry.Source) != "" {
355			return resolve(entry.Source)
356		}
357		return ""
358	}
