1	package skills
2	
3	import (
4		"errors"
5		"fmt"
6		"io/fs"
7		"os"
8		"path/filepath"
9		"strings"
10	)
11	
12	// Options controls Install behavior.
13	type Options struct {
14		// Force overwrites pre-existing real-file destinations. When false, existing
15		// real-file skill directories are preserved (per-skill skip). Pre-existing
16		// symlink destinations are ALWAYS removed regardless of Force.
17		Force bool
18	}
19	
20	// Install copies skills from src into <projectRoot>/.agents/skills/<name>/ and
21	// <projectRoot>/.claude/skills/<name>/ as real files. Never creates symlinks.
22	//
23	// Source layouts:
24	//   - Top-level skill dirs (embed.FS bootstrap): src has "<skillName>/..."
25	//   - Plugin layout (os.DirFS over plugin root): src has ".agents/skills/<skillName>";
26	//     when that path is a broken symlink (tarball authored with symlinks),
27	//     falls back to "skills/<skillName>".
28	func Install(src fs.FS, projectRoot string, opts Options) error {
29		if projectRoot == "" {
30			return errors.New("skills.Install: projectRoot is empty")
31		}
32	
33		skillNames, sources, err := discoverSkills(src)
34		if err != nil {
35			return fmt.Errorf("discover skills: %w", err)
36		}
37	
38		for _, name := range skillNames {
39			if err := validateSkillName(name); err != nil {
40				return err
41			}
42		}
43	
44		targets := []string{
45			filepath.Join(projectRoot, ".agents", "skills"),
46			filepath.Join(projectRoot, ".claude", "skills"),
47		}
48	
49		// Pre-flight: validate every destination resolves inside projectRoot.
50		// Done before any write so traversal/escape inputs error out cleanly.
51		absRoot, err := filepath.Abs(projectRoot)
52		if err != nil {
53			return fmt.Errorf("resolve projectRoot: %w", err)
54		}
55		for _, target := range targets {
56			for _, name := range skillNames {
57				destDir := filepath.Join(target, name)
58				// Symlinks are always removed and replaced with real files; skip the
59				// within-root check for them (the replacement write will be inside
60				// the root). This handles pre-migration symlinks pointing to
61				// locations outside the project root.
62				if info, err := os.Lstat(destDir); err == nil && info.Mode()&os.ModeSymlink != 0 {
63					continue
64				}
65				if err := assertWithinRoot(destDir, absRoot); err != nil {
66					return err
67				}
68			}
69		}
70	
71		// Ensure target parents exist after validation.
72		for _, t := range targets {
73			if err := os.MkdirAll(t, 0o755); err != nil {
74				return fmt.Errorf("create %s: %w", t, err)
75			}
76			// Reject if target itself is a symlink escaping projectRoot.
77			if err := assertWithinRoot(t, absRoot); err != nil {
78				return err
79			}
80		}
81	
82		for i, name := range skillNames {
83			srcSub := sources[i]
84			for _, target := range targets {
85				destDir := filepath.Join(target, name)
86				info, lerr := os.Lstat(destDir)
87				if lerr == nil {
88					if info.Mode()&os.ModeSymlink != 0 {
89						// Symlink: always remove and replace, regardless of Force.
90						if err := os.Remove(destDir); err != nil {
91							return fmt.Errorf("remove pre-existing symlink %s: %w", destDir, err)
92						}
93					} else if !opts.Force {
94						// Real-file destination + !Force: skip per-skill (whole dir).
95						continue
96					} else {
97						// Real-file destination + Force: overwrite by removing first.
98						if err := os.RemoveAll(destDir); err != nil {
99							return fmt.Errorf("remove existing dir %s: %w", destDir, err)
100						}
101					}
102				}
103				if err := copyFromFS(srcSub, destDir); err != nil {
104					return fmt.Errorf("copy skill %q: %w", name, err)
105				}
106			}
107		}
108	
109		return nil
110	}
111	
112	// discoverSkills inspects src and returns parallel slices of skill names and
113	// per-skill sub-FSes rooted at the skill content. Handles both bootstrap
114	// (top-level) and plugin (.agents/skills) layouts.
115	func discoverSkills(src fs.FS) ([]string, []fs.FS, error) {
116		if info, err := fs.Stat(src, ".agents/skills"); err == nil && info.IsDir() {
117			entries, err := fs.ReadDir(src, ".agents/skills")
118			if err != nil {
119				return nil, nil, err
120			}
121			var names []string
122			var subs []fs.FS
123			for _, e := range entries {
124				name := e.Name()
125				primary := ".agents/skills/" + name
126				// Try the canonical path first. fs.Stat follows symlinks under os.DirFS,
127				// so a broken symlink yields an error here.
128				if _, statErr := fs.Stat(src, primary); statErr == nil {
129					sub, err := fs.Sub(src, primary)
130					if err != nil {
131						return nil, nil, err
132					}
133					names = append(names, name)
134					subs = append(subs, sub)
135					continue
136				}
137				// Broken symlink (tarball case) — fall back to skills/<name>.
138				fallback := "skills/" + name
139				if _, statErr := fs.Stat(src, fallback); statErr != nil {
140					continue
141				}
142				sub, err := fs.Sub(src, fallback)
143				if err != nil {
144					return nil, nil, err
145				}
146				names = append(names, name)
147				subs = append(subs, sub)
148			}
149			return names, subs, nil
150		}
151	
152		// Default layout: top-level entries are skill directories.
153		entries, err := fs.ReadDir(src, ".")
154		if err != nil {
155			return nil, nil, err
156		}
157		var names []string
158		var subs []fs.FS
159		for _, e := range entries {
160			if !e.IsDir() {
161				continue
162			}
163			sub, err := fs.Sub(src, e.Name())
164			if err != nil {
165				return nil, nil, err
166			}
167			names = append(names, e.Name())
168			subs = append(subs, sub)
169		}
170		return names, subs, nil
171	}
172	
173	// validateSkillName rejects names that could escape the destination tree.
174	func validateSkillName(name string) error {
175		if name == "" || name == "." || name == ".." {
176			return fmt.Errorf("skills.Install: invalid skill name %q", name)
177		}
178		if strings.ContainsAny(name, `/\`) {
179			return fmt.Errorf("skills.Install: skill name contains path separator: %q", name)
180		}
181		if filepath.IsAbs(name) {
182			return fmt.Errorf("skills.Install: skill name is absolute: %q", name)
183		}
184		if strings.Contains(name, "..") {
185			return fmt.Errorf("skills.Install: skill name contains parent reference: %q", name)
186		}
187		return nil
188	}
189	
190	// assertWithinRoot resolves dest (and the existing portion of its path) and
191	// returns an error if it escapes absRoot via symlinks or absolute paths.
192	func assertWithinRoot(dest, absRoot string) error {
193		abs, err := filepath.Abs(dest)
194		if err != nil {
195			return fmt.Errorf("resolve %s: %w", dest, err)
196		}
197		// Walk upward to find an existing ancestor and EvalSymlinks on it; this
198		// catches symlink-escapes even when the leaf does not yet exist.
199		check := abs
200		for {
201			if _, err := os.Lstat(check); err == nil {
202				resolved, err := filepath.EvalSymlinks(check)
203				if err != nil {
204					return fmt.Errorf("resolve symlinks for %s: %w", check, err)
205				}
206				resolvedRoot, rerr := filepath.EvalSymlinks(absRoot)
207				if rerr != nil {
208					// projectRoot may not exist yet — fall back to lexical compare.
209					resolvedRoot = absRoot
210				}
211				if !pathHasPrefix(resolved, resolvedRoot) {
212					return fmt.Errorf("skills.Install: path %s escapes project root %s", dest, absRoot)
213				}
214				break
215			}
216			parent := filepath.Dir(check)
217			if parent == check {
218				break
219			}
220			check = parent
221		}
222		if !pathHasPrefix(abs, absRoot) {
223			return fmt.Errorf("skills.Install: path %s escapes project root %s", dest, absRoot)
224		}
225		return nil
226	}
227	
228	func pathHasPrefix(p, prefix string) bool {
229		if p == prefix {
230			return true
231		}
232		sep := string(filepath.Separator)
233		if !strings.HasSuffix(prefix, sep) {
234			prefix += sep
235		}
236		return strings.HasPrefix(p, prefix)
237	}
238	
239	// copyFromFS recursively copies src (rooted at ".") into destDir as real files.
240	// Symlinks in the source are skipped (never materialized) — see FEAT-015
241	// "Cross-platform invariant".
242	func copyFromFS(src fs.FS, destDir string) error {
243		if err := os.MkdirAll(destDir, 0o755); err != nil {
244			return err
245		}
246		return fs.WalkDir(src, ".", func(p string, d fs.DirEntry, err error) error {
247			if err != nil {
248				return err
249			}
250			if p == "." {
251				return nil
252			}
253			// Reject actual path-traversal components ("..") but not substrings
254			// like SvelteKit's [...param] catch-all route syntax.
255			for _, component := range strings.Split(p, "/") {
256				if component == ".." {
257					return fmt.Errorf("invalid path in source: %s", p)
258				}
259			}
260			target := filepath.Join(destDir, p)
261			if d.IsDir() {
262				return os.MkdirAll(target, 0o755)
263			}
264			if d.Type()&os.ModeSymlink != 0 {
265				// Skip plugin-source symlinks — never materialize.
266				return nil
267			}
268			data, rerr := fs.ReadFile(src, p)
269			if rerr != nil {
270				return rerr
271			}
272			return os.WriteFile(target, data, 0o644)
273		})
274	}
