35	// ValidateContent checks one SKILL.md payload against the DDx skill metadata contract.
36	func ValidateContent(name string, data []byte) []Issue {
37		frontmatter, body, ok := splitSkillFrontmatter(data)
38		if !ok {
39			return []Issue{{Path: name, Message: "missing YAML frontmatter delimited by ---"}}
40		}
41	
42		var meta skillFrontmatter
43		if err := yaml.Unmarshal(frontmatter, &meta); err != nil {
44			return []Issue{{Path: name, Message: fmt.Sprintf("invalid YAML frontmatter: %v", err)}}
45		}
46	
47		var issues []Issue
48		if meta.Skill != nil {
49			issues = append(issues, Issue{Path: name, Message: "nested `skill:` frontmatter is not allowed; use top-level `name` and `description`"})
50		}
51		if strings.TrimSpace(meta.Name) == "" {
52			issues = append(issues, Issue{Path: name, Message: "missing required top-level `name` field"})
53		}
54		if strings.TrimSpace(meta.Description) == "" {
55			issues = append(issues, Issue{Path: name, Message: "missing required top-level `description` field"})
56		}
57		if strings.TrimSpace(string(body)) == "" {
58			issues = append(issues, Issue{Path: name, Message: "markdown body is empty"})
59		}
60		if strings.TrimSpace(meta.ArgumentHint) == "" && bytes.Contains(frontmatter, []byte("argument-hint:")) {
61			issues = append(issues, Issue{Path: name, Message: "`argument-hint` must not be empty when present"})
62		}
63		return issues
64	}
65	
66	// ValidatePaths checks one or more files or directories recursively for SKILL.md files.
67	func ValidatePaths(paths []string) ([]string, []Issue) {
68		seen := map[string]bool{}
69		var files []string
70		var issues []Issue
71	
72		for _, root := range paths {
73			if strings.TrimSpace(root) == "" {
74				continue
75			}
76	
77			info, err := os.Stat(root)
78			if err != nil {
79				issues = append(issues, Issue{Path: root, Message: err.Error()})
80				continue
81			}
82	
83			if info.IsDir() {
84				err = filepath.WalkDir(root, func(path string, d fs.DirEntry, err error) error {
85					if err != nil {
86						issues = append(issues, Issue{Path: path, Message: err.Error()})
87						return nil
88					}
89					if d.IsDir() {
90						return nil
91					}
92					if filepath.Base(path) != "SKILL.md" {
93						return nil
94					}
95					files = appendIfNew(files, seen, path)
96					return nil
97				})
98				if err != nil {
99					issues = append(issues, Issue{Path: root, Message: err.Error()})
100				}
101				continue
102			}
103	
104			if filepath.Base(root) != "SKILL.md" {
105				issues = append(issues, Issue{Path: root, Message: "expected a SKILL.md file or a directory containing skills"})
106				continue
107			}
108			files = appendIfNew(files, seen, root)
109		}
110	
111		sort.Strings(files)
112		for _, path := range files {
113			data, err := os.ReadFile(path)
114			if err != nil {
115				issues = append(issues, Issue{Path: path, Message: err.Error()})
116				continue
117			}
118			issues = append(issues, ValidateContent(path, data)...)
119		}
120	
121		if len(files) == 0 && len(issues) == 0 {
122			issues = append(issues, Issue{Message: "no SKILL.md files found"})
123		}
124	
125		return files, issues
126	}
127	
128	func appendIfNew(files []string, seen map[string]bool, path string) []string {
129		if seen[path] {
130			return files
131		}
132		seen[path] = true
133		return append(files, path)
134	}
135	
136	func splitSkillFrontmatter(data []byte) ([]byte, []byte, bool) {
137		lines := bytes.Split(data, []byte("\n"))
138		if len(lines) < 3 || string(lines[0]) != "---" {
139			return nil, nil, false
140		}
141	
142		end := -1
143		for i := 1; i < len(lines); i++ {
144			if string(lines[i]) == "---" {
145				end = i
146				break
147			}
148		}
149		if end == -1 {
150			return nil, nil, false
151		}
152	
153		frontmatter := bytes.Join(lines[1:end], []byte("\n"))
154		body := bytes.Join(lines[end+1:], []byte("\n"))
155		return frontmatter, body, true
156	}
